import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Search, Loader2, RefreshCw, Database, Sparkles, ExternalLink, BarChart2, BrainCircuit, X, Globe, TrendingUp, TrendingDown } from 'lucide-react';
import InsightCard from './InsightCard';
import BulkInsightManager from './BulkInsightManager';
import IntelligentTrackingManager from './IntelligentTrackingManager';
import InsightChatbot from './InsightChatbot';
import MarketOverview from './MarketOverview';
import { getTrackedItems, TrackedItem, getTrackedIndices, addTrackedItem, removeTrackedItem } from '../../services/trackingStorage';
import { fetchMarketInsights } from '../../services/geminiService';
import { fetchMarketIndices, fetchStockQuote } from '../../services/dataService';
import { Insight, InsightResultItem, IntelligentState, MarketIndexData, SectoralData } from '../../types/trackingTypes';
import { FundSearchResult } from '../../types';
import { HEADER_INDICES } from '../../types/constants';
import { useInsightExtraction } from '../../hooks/useInsightExtraction';

interface TrackingDashboardProps {
  onSelectStock: (symbol: string, name: string) => void;
  onSelectFund: (fund: FundSearchResult) => void;

  // Market Data (Lifted)
  marketIndices: MarketIndexData[];
  setMarketIndices: React.Dispatch<React.SetStateAction<MarketIndexData[]>>;
  moversData: any[];
  setMoversData: React.Dispatch<React.SetStateAction<any[]>>;
  sectoralData: SectoralData | null;
  setSectoralData: React.Dispatch<React.SetStateAction<SectoralData | null>>;

  // Deep Dive State
  bulkResults: Record<string, InsightResultItem[]>;
  setBulkResults: React.Dispatch<React.SetStateAction<Record<string, InsightResultItem[]>>>;
  bulkStatus: 'idle' | 'initializing' | 'polling' | 'completed' | 'error';
  setBulkStatus: React.Dispatch<React.SetStateAction<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>>;
  bulkProgress: { completed: number; total: number };
  setBulkProgress: React.Dispatch<React.SetStateAction<{ completed: number; total: number }>>;
  requestId: string | null;
  setRequestId: React.Dispatch<React.SetStateAction<string | null>>;
  // Intelligent State
  intelligentExtraction: ReturnType<typeof useInsightExtraction>;
  intelligentState: IntelligentState;
  setIntelligentState: React.Dispatch<React.SetStateAction<IntelligentState>>;
}

const TrackingDashboard: React.FC<TrackingDashboardProps> = ({ 
  onSelectStock, 
  onSelectFund,
  marketIndices,
  setMarketIndices,
  moversData,
  setMoversData,
  sectoralData,
  setSectoralData,
  bulkResults,
  setBulkResults,
  bulkStatus,
  setBulkStatus,
  bulkProgress,
  setBulkProgress,
  requestId,
  setRequestId,
  intelligentExtraction,
  intelligentState,
  setIntelligentState
}) => {
  const [activeStreamTab, setActiveStreamTab] = useState<'DEEP_DIVE' | 'AI' | 'INTELLIGENT' | 'MARKET'>('MARKET');

  // Global Data State
  const [entities, setEntities] = useState<TrackedItem[]>([]);
  const [trackedIndices, setTrackedIndices] = useState<string[]>([]);

  const [loadingIndices, setLoadingIndices] = useState(false);
  const [loadingPortfolio, setLoadingPortfolio] = useState(false);

  // Market News State
  const [insights, setInsights] = useState<Insight[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Chat State
  const [chatContext, setChatContext] = useState<any[] | null>(null);

  // Local stats for display
  const [intelligentStats, setIntelligentStats] = useState<{ filtered: number; total: number; ignoredList: string[] }>({ filtered: 0, total: 0, ignoredList: [] });
  const [showIgnoredPopover, setShowIgnoredPopover] = useState(false);
  const ignoredPopoverRef = useRef<HTMLDivElement>(null);

  const loadIndices = async () => {
      setLoadingIndices(true);
      const data = await fetchMarketIndices();
      setMarketIndices(data);
      setLoadingIndices(false);
  };

  // Helper to format Quote Data
  const processQuoteData = (quote: any) => {
      return {
          symbol: quote.metaData.symbol,
          companyName: quote.metaData.companyName,
          lastPrice: quote.tradeInfo.lastPrice, 
          change: quote.metaData.change,
          pChange: quote.metaData.pChange,
          pdSymbolPe: quote.secInfo?.pdSymbolPe,
          pdSectorPe: quote.secInfo?.pdSectorPe,
          yearHigh: quote.priceInfo?.yearHigh,
          yearLow: quote.priceInfo?.yearLow,
          sector: quote.secInfo?.sector,
          basicIndustry: quote.secInfo?.basicIndustry,
          indexList: quote.secInfo?.indexList || [],
          delivery: quote.tradeInfo?.deliveryToTradedQuantity || quote.secInfo?.deliveryTotradedQuantity,
          pdSectorInd: quote.secInfo?.pdSectorInd,
          macro: quote.secInfo?.macro,
          industryInfo: quote.secInfo?.industryInfo
      };
  };

  const loadPortfolioData = async () => {
      setLoadingPortfolio(true);
      try {
          const trackedStocks = getTrackedItems().filter(i => i.type === 'STOCK');

          if (trackedStocks.length === 0) {
              setMoversData([]);
              setLoadingPortfolio(false);
              return;
          }

          // Fetch quotes in parallel
          const results = await Promise.all(trackedStocks.map(async (item) => {
              try {
                  const quote = await fetchStockQuote(item.id);
                  if (quote && quote.metaData) {
                      return processQuoteData(quote);
                  }
                  return null;
              } catch (e) {
                  console.error(`Failed to fetch quote for ${item.id}`, e);
                  return null;
              }
          }));

          const validResults = results.filter(r => r !== null);
          setMoversData(validResults);
      } catch (e) {
          console.error("Error loading portfolio data", e);
      } finally {
          setLoadingPortfolio(false);
      }
  };

  // Portfolio Management Handlers
  const handleAddMover = async (symbol: string) => {
      // 1. Add to tracking
      addTrackedItem({ id: symbol, name: symbol, symbol, type: 'STOCK' });

      // 2. Fetch data if not already present
      if (!moversData.find(m => m.symbol === symbol)) {
          try {
              const quote = await fetchStockQuote(symbol);
              if (quote && quote.metaData) {
                  const processed = processQuoteData(quote);
                  setMoversData(prev => [...prev, processed]);
              }
          } catch (e) {
              console.error("Failed to add mover", e);
          }
      }
  };

  const handleRefreshMover = async (symbol: string) => {
      try {
          const quote = await fetchStockQuote(symbol);
          if (quote && quote.metaData) {
              const processed = processQuoteData(quote);
              setMoversData(prev => prev.map(m => m.symbol === symbol ? processed : m));
          }
      } catch(e) {
          console.error(`Failed to refresh ${symbol}`, e);
      }
  };

  const handleRemoveMover = (symbol: string) => {
      removeTrackedItem(symbol, 'STOCK');
      setMoversData(prev => prev.filter(m => m.symbol !== symbol));
  };

  // Load initial data and listen for updates
  useEffect(() => {
    const loadItems = () => {
        setEntities(getTrackedItems());
        setTrackedIndices(getTrackedIndices());
    };

    loadItems();

    // Initial Data Loads
    if (marketIndices.length === 0) loadIndices();
    if (moversData.length === 0) loadPortfolioData();

    const handleStorageUpdate = () => {
        loadItems();
        // Optionally reload portfolio data on storage update if needed, 
        // but manual add/remove handles state locally for smoother UX.
        // loadPortfolioData(); 
    };

    window.addEventListener('fundflow_tracking_update', handleStorageUpdate);
    return () => window.removeEventListener('fundflow_tracking_update', handleStorageUpdate);
  }, []); 

  // Close popover on click outside
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (ignoredPopoverRef.current && !ignoredPopoverRef.current.contains(event.target as Node)) {
              setShowIgnoredPopover(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const fetchInsights = async () => {
     if (entities.length === 0) return;
     setLoadingInsights(true);
     try {
         const data = await fetchMarketInsights(entities);
         setInsights(data);
     } catch (err) {
         console.error(err);
     } finally {
         setLoadingInsights(false);
     }
  };

  const filteredInsights = useMemo(() => {
    let filtered = insights;
    if (searchQuery) {
        const lowerQ = searchQuery.toLowerCase();
        filtered = filtered.filter(i => 
        i.title.toLowerCase().includes(lowerQ) || 
        i.content.toLowerCase().includes(lowerQ)
        );
    }
    return filtered.map(item => {
        const entity = entities.find(e => e.id === item.entityId);
        return { ...item, entityName: entity?.name || 'Unknown', entitySymbol: entity?.symbol };
    }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [insights, entities, searchQuery]);

  // Header Indices Data
  const headerIndicesData = useMemo(() => {
      return marketIndices.filter(idx => HEADER_INDICES.includes(idx.index));
  }, [marketIndices]);

  return (
    <div className="flex flex-col gap-6 animate-fade-in w-full max-w-7xl mx-auto relative">

      {/* Header & Tabs */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
         <div className="flex flex-col lg:flex-row justify-between items-start gap-6 mb-6">
            <div className="flex-1">
              <h2 className="text-2xl font-bold text-gray-900">Market Intelligence</h2>
              <p className="text-gray-500 text-sm relative mt-1">
                {activeStreamTab === 'INTELLIGENT' 
                  ? (
                    <span>
                      Showing <strong>{intelligentStats.filtered}</strong> potential stocks from index ({intelligentStats.total} active)
                      {intelligentStats.ignoredList.length > 0 && (
                          <span className="ml-1 text-red-400">
                              • <span 
                                  className="cursor-pointer underline decoration-dotted hover:text-red-600"
                                  onClick={() => setShowIgnoredPopover(!showIgnoredPopover)}
                                >
                                  {intelligentStats.ignoredList.length} ignored
                                </span>
                          </span>
                      )}
                    </span>
                  )
                  : activeStreamTab === 'MARKET' ? "Overview of global and tracked indices"
                  : `Tracking ${entities.length} items in your portfolio`
                }
              </p>

              {/* Ignored List Popover */}
              {showIgnoredPopover && intelligentStats.ignoredList.length > 0 && (
                  <div 
                    ref={ignoredPopoverRef}
                    className="absolute z-50 mt-2 bg-white border border-gray-200 rounded-lg shadow-xl p-3 w-64 animate-fade-in left-0 md:left-auto"
                  >
                      <div className="flex justify-between items-center mb-2 pb-2 border-b border-gray-100">
                          <h4 className="text-xs font-bold text-gray-700">Ignored in this Index</h4>
                          <button onClick={() => setShowIgnoredPopover(false)} className="text-gray-400 hover:text-gray-600">
                              <X size={14} />
                          </button>
                      </div>
                      <div className="max-h-48 overflow-y-auto space-y-1">
                          {intelligentStats.ignoredList.map(sym => (
                              <div 
                                key={sym} 
                                className="text-xs text-gray-600 px-2 py-1 rounded hover:bg-gray-50 cursor-pointer flex justify-between"
                                onClick={() => { onSelectStock(sym, sym); setShowIgnoredPopover(false); }}
                              >
                                  <span>{sym}</span>
                                  <ExternalLink size={10} className="text-gray-400 opacity-50" />
                              </div>
                          ))}
                      </div>
                  </div>
              )}
            </div>

            {/* Subtle Market Header Stats - Vertical Stack */}
            <div className="flex flex-col gap-2 items-end min-w-[200px]">
                <div className="flex items-center gap-2 mb-1">
                     <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">Live Indices</span>
                     <button 
                         onClick={loadIndices}
                         disabled={loadingIndices}
                         className="p-1 text-gray-400 hover:text-indigo-600 transition-colors"
                         title="Refresh Indices"
                     >
                         <RefreshCw size={12} className={loadingIndices ? 'animate-spin' : ''} />
                     </button>
                </div>
                {headerIndicesData.length > 0 ? (
                    headerIndicesData.map(idx => {
                        const isPos = idx.percentChange >= 0;
                        const tooltipText = `PE: ${idx.pe}\nPrevious Close: ${idx.previousClose}\nOpen: ${idx.open}\nHigh: ${idx.high}\nLow: ${idx.low}\nYear High: ${idx.yearHigh}\nYear Low: ${idx.yearLow}`;

                        return (
                            <div 
                                key={idx.index} 
                                className="flex items-center justify-between gap-3 bg-gray-50 px-3 py-1.5 rounded-lg border border-gray-100 text-xs cursor-help hover:bg-gray-100 hover:border-gray-300 transition-colors w-full"
                                title={tooltipText}
                            >
                                <span className="font-semibold text-gray-700">{idx.index}</span>
                                <div className="flex items-center gap-2">
                                    <span className="font-mono text-gray-800">{idx.last.toLocaleString()}</span>
                                    <span className={`font-medium w-12 text-right ${isPos ? 'text-green-600' : 'text-red-600'}`}>
                                        {isPos ? '+' : ''}{idx.percentChange.toFixed(2)}%
                                    </span>
                                </div>
                            </div>
                        );
                    })
                ) : (
                    <div className="text-xs text-gray-400 italic">Loading indices...</div>
                )}
            </div>
         </div>

         {/* Tab Navigation - Updated Order */}
         <div className="flex items-center gap-6 border-b border-gray-200 overflow-x-auto">
             <button
                onClick={() => setActiveStreamTab('MARKET')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'MARKET' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <Globe size={18} />
                Market Overview
             </button>
             <button
                onClick={() => setActiveStreamTab('INTELLIGENT')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'INTELLIGENT' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <BrainCircuit size={18} />
                Intelligent Tracking
             </button>
             <button
                onClick={() => setActiveStreamTab('DEEP_DIVE')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'DEEP_DIVE' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <BarChart2 size={18} />
                Tracked Assets
             </button>
             <button
                onClick={() => setActiveStreamTab('AI')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'AI' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <Sparkles size={18} />
                Market News
             </button>
         </div>
      </div>

      {/* Main Content Area */}
      <div className="min-h-[500px]">

         {/* MARKET OVERVIEW */}
         {activeStreamTab === 'MARKET' && (
             <MarketOverview 
                indicesData={marketIndices} 
                trackedIndices={trackedIndices}
                onRefresh={loadIndices}
                loading={loadingIndices}
                onSelectStock={onSelectStock}

                // Pass Portfolio Mover Props managed by Dashboard
                moversData={moversData}
                setMoversData={setMoversData}
                onRefreshPortfolio={loadPortfolioData}
                loadingPortfolio={loadingPortfolio}
                onAddMover={handleAddMover}
                onRefreshMover={handleRefreshMover}
                onRemoveMover={handleRemoveMover}

                sectoralData={sectoralData}
                setSectoralData={setSectoralData}
             />
         )}

         {/* INTELLIGENT TRACKING VIEW */}
         {activeStreamTab === 'INTELLIGENT' && (
            <IntelligentTrackingManager 
                onOpenChat={(ctx) => setChatContext(ctx)}
                onSelectStock={onSelectStock}
                extractionData={intelligentExtraction}
                onStatsUpdate={setIntelligentStats}
                // Pass persisted state props
                viewState={intelligentState}
                setViewState={setIntelligentState}
            />
         )}

         {/* TRACKED ASSETS (Deep Dive) VIEW */}
         {activeStreamTab === 'DEEP_DIVE' && (
            <BulkInsightManager 
                items={entities}
                results={bulkResults}
                setResults={setBulkResults}
                status={bulkStatus}
                setStatus={setBulkStatus}
                progress={bulkProgress}
                setProgress={setBulkProgress}
                requestId={requestId}
                setRequestId={setRequestId}
                onOpenChat={(ctx) => setChatContext(ctx)}
                onSelectStock={onSelectStock}
            />
         )}

         {/* MARKET NEWS VIEW */}
         {activeStreamTab === 'AI' && (
            <div className="space-y-4">
               <div className="flex items-center justify-between pb-2">
                  <p className="text-xs text-gray-500">
                      {loadingInsights 
                        ? 'Analyzing market data...' 
                        : `${filteredInsights.length} insights generated via Gemini`
                      }
                  </p>
                  <button 
                      onClick={fetchInsights} 
                      disabled={loadingInsights}
                      className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 transition-colors text-sm font-medium"
                  >
                      {loadingInsights ? <Loader2 size={16} className="animate-spin"/> : <RefreshCw size={16} />}
                      Generate New Insights
                  </button>
               </div>

               {loadingInsights && filteredInsights.length === 0 ? (
                  <div className="p-12 flex flex-col items-center justify-center space-y-3 bg-white rounded-xl border border-gray-100">
                      <Loader2 size={32} className="animate-spin text-indigo-600" />
                      <p className="text-gray-500 text-sm">Gathering intelligent insights...</p>
                  </div>
               ) : filteredInsights.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                      {filteredInsights.map(insight => (
                          <InsightCard key={insight.id} insight={insight} />
                      ))}
                  </div>
               ) : (
                  <div className="text-center py-16 bg-white rounded-xl border border-dashed border-gray-300">
                      <Sparkles size={48} className="mx-auto text-indigo-200 mb-4" />
                      <h3 className="text-lg font-medium text-gray-900">AI Market News</h3>
                      <p className="text-gray-500 max-w-sm mx-auto mt-2">
                          Get real-time summaries and sentiment analysis for your portfolio items powered by Gemini 2.5.
                      </p>
                      <button 
                          onClick={fetchInsights}
                          className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded-full font-medium hover:bg-indigo-700 transition-shadow shadow-md"
                      >
                          Generate News
                      </button>
                  </div>
               )}
            </div>
         )}
      </div>

      {/* Floating Chatbot Overlay */}
      {chatContext && (
          <InsightChatbot 
              contextData={chatContext} 
              onClose={() => setChatContext(null)} 
          />
      )}
    </div>
  );
};

export default TrackingDashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { MarketIndexData, FiiDiiData, SectoralData } from '../../types/trackingTypes';
import { addTrackedIndex, removeTrackedIndex } from '../../services/trackingStorage';
import { fetchFiiDiiActivity, fetchSectoralAnalysis } from '../../services/dataService';
import { MARKET_OVERVIEW_INDICES, HEADER_INDICES } from '../../types/constants.ts'
import { Activity, Search, RefreshCw, CheckSquare, Square, Loader2, TrendingUp, ExternalLink } from 'lucide-react';
import IndexInsightsWidget from './IndexInsightsWidget';
import PortfolioUpdates from './PortfolioMovers';
import SectoralPulse from './SectoralPulse';

interface MarketOverviewProps {
  indicesData: MarketIndexData[];
  trackedIndices: string[];
  onRefresh: () => void;
  loading: boolean;
  onSelectStock?: (symbol: string, name: string) => void;

  // Portfolio Mover Props
  moversData: any[];
  setMoversData: React.Dispatch<React.SetStateAction<any[]>>;
  onRefreshPortfolio?: () => Promise<void>; // New prop for refreshing tracked portfolio
  loadingPortfolio?: boolean;
  onAddMover: (symbol: string) => Promise<void>;
  onRefreshMover: (symbol: string) => Promise<void>;
  onRemoveMover: (symbol: string) => void;

  sectoralData: SectoralData | null;
  setSectoralData: React.Dispatch<React.SetStateAction<SectoralData | null>>;
}

const IndexRow: React.FC<{ 
    data: MarketIndexData, 
    isTracked: boolean, 
    onToggle: () => void,
    isAlternate?: boolean,
    onSelectStock?: (symbol: string, name: string) => void,
    onAddMover: (symbol: string) => void,
    addedMovers: string[]
}> = ({ data, isTracked, onToggle, isAlternate, onSelectStock, onAddMover, addedMovers }) => {

  const isPositive = data.percentChange >= 0;
  const colorClass = isPositive ? 'text-green-600' : 'text-red-600';

  // Calculate 1W return
  const oneWeekReturn = data.oneWeekAgoVal 
    ? ((data.last - data.oneWeekAgoVal) / data.oneWeekAgoVal * 100).toFixed(2) 
    : '-';

  // Breadth
  const advances = parseInt(data.advances || "0", 10);
  const declines = parseInt(data.declines || "0", 10);
  const total = advances + declines;
  const advanceWidth = total > 0 ? (advances / total) * 100 : 50;

  // 52 Week Range
  const rangePos = data.yearHigh && data.yearLow
    ? ((data.last - data.yearLow) / (data.yearHigh - data.yearLow)) * 100
    : 0;

  return (
    <tr className={`hover:bg-indigo-50/30 transition-colors border-b border-gray-50 group ${isAlternate ? 'bg-gray-50/30' : ''} ${isTracked ? 'bg-indigo-50/10' : ''}`}>
        {/* Track Checkbox */}
        <td className="px-4 py-3">
            <button 
                onClick={(e) => { e.stopPropagation(); onToggle(); }}
                className={`transition-colors ${isTracked ? 'text-indigo-600' : 'text-gray-300 group-hover:text-gray-400'}`}
                title={isTracked ? "Remove from Watchlist" : "Add to Watchlist"}
            >
                {isTracked ? <CheckSquare size={18} /> : <Square size={18} />}
            </button>
        </td>

        <td className="px-4 py-3">
            <div className="flex items-center gap-1.5">
                <span className="font-semibold text-gray-800 text-xs sm:text-sm">{data.index}</span>

                {/* Integrate Insights Widget - Self Managed Mode */}
                <IndexInsightsWidget 
                    indexName={data.indexSymbol} 
                    onAddToMover={onAddMover} 
                    onNavigateStock={onSelectStock} 
                    addedSymbols={addedMovers} 
                />

                {/* External Link to NSE Index Tracker */}
                <a 
                    href={`https://www.nseindia.com/index-tracker/${encodeURIComponent(data.indexSymbol)}`} 
                    target="_blank" 
                    rel="noreferrer"
                    className="text-gray-300 hover:text-indigo-600 transition-colors opacity-0 group-hover:opacity-100"
                    title={`View ${data.index} on NSE`}
                    onClick={(e) => e.stopPropagation()}
                >
                    <ExternalLink size={12} />
                </a>
            </div>
        </td>
        <td className="px-4 py-3 text-right font-mono text-gray-700">{data.last?.toLocaleString()}</td>
        <td className={`px-4 py-3 text-right font-medium ${colorClass}`}>
            {isPositive ? '+' : ''}{data.percentChange.toFixed(2)}%
        </td>

        {/* Valuation (PE | PB | DY) */}
        <td className="px-4 py-3 text-center text-gray-600 hidden sm:table-cell">
            <div className="flex items-center justify-center gap-2 text-[11px]">
                <span className="font-medium bg-gray-100 px-1.5 py-0.5 rounded text-gray-700" title="P/E">{data.pe || '-'}</span>
                <span className="text-gray-300">|</span>
                <span className="text-gray-500" title="P/B">{data.pb || '-'}</span>
                <span className="text-gray-300">|</span>
                <span className="text-gray-500" title="Yield">{data.dy || '-'}</span>
            </div>
        </td>

        {/* Returns */}
        <td className="px-4 py-3 text-center hidden md:table-cell">
            <div className="flex items-center justify-center gap-3 text-[11px]">
                <div className="flex flex-col items-center w-8">
                    <span className={parseFloat(oneWeekReturn) >= 0 ? 'text-green-600 font-medium' : 'text-red-600 font-medium'}>
                        {oneWeekReturn}%
                    </span>
                    <span className="text-[9px] text-gray-400">1W</span>
                </div>
                <div className="flex flex-col items-center w-8">
                    <span className={data.perChange30d >= 0 ? 'text-green-600 font-medium' : 'text-red-600 font-medium'}>
                        {data.perChange30d.toFixed(1)}%
                    </span>
                    <span className="text-[9px] text-gray-400">1M</span>
                </div>
                <div className="flex flex-col items-center w-8">
                    <span className={data.perChange365d >= 0 ? 'text-green-600 font-medium' : 'text-red-600 font-medium'}>
                        {data.perChange365d.toFixed(1)}%
                    </span>
                    <span className="text-[9px] text-gray-400">1Y</span>
                </div>
            </div>
        </td>

        {/* 52W Range */}
        <td className="px-4 py-3 hidden lg:table-cell">
            <div className="flex flex-col gap-1 w-full max-w-[120px] mx-auto">
                <div className="flex justify-between text-[9px] text-gray-400">
                    <span>{data.yearLow?.toLocaleString()}</span>
                    <span>{data.yearHigh?.toLocaleString()}</span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden relative">
                    <div 
                        className="absolute h-full w-1.5 bg-indigo-600 rounded-full top-0 ml-[-3px]" 
                        style={{ left: `${Math.min(Math.max(rangePos, 0), 100)}%` }}
                    ></div>
                </div>
            </div>
        </td>

        {/* Breadth */}
        <td className="px-4 py-3 hidden xl:table-cell">
            <div className="flex flex-col gap-1 w-full max-w-[80px] mx-auto">
                <div className="flex w-full h-1.5 rounded-full overflow-hidden bg-gray-200">
                    <div className="bg-green-500 h-full" style={{ width: `${advanceWidth}%` }}></div>
                    <div className="bg-red-500 h-full" style={{ width: `${100 - advanceWidth}%` }}></div>
                </div>
                <div className="flex justify-between text-[9px]">
                    <span className="text-green-600 font-medium">{advances}</span>
                    <span className="text-red-600 font-medium">{declines}</span>
                </div>
            </div>
        </td>
    </tr>
  );
};

export const MarketOverview: React.FC<MarketOverviewProps> = ({ 
    indicesData, 
    trackedIndices, 
    onRefresh, 
    loading, 
    onSelectStock, 
    moversData, 
    setMoversData,
    onRefreshPortfolio,
    loadingPortfolio,
    onAddMover,
    onRefreshMover,
    onRemoveMover,
    sectoralData,
    setSectoralData
}) => {
  const [filterQuery, setFilterQuery] = useState('');
  const [fiiData, setFiiData] = useState<FiiDiiData | null>(null);
  const [loadingSector, setLoadingSector] = useState(false);
  const [sectorDuration, setSectorDuration] = useState('1D'); // Default duration

  // Use all indices available from the API and filter locally
  const filteredData = useMemo(() => {
      let data = [...indicesData]; // Copy array before sorting

      if (filterQuery) {
          const lowerQ = filterQuery.toLowerCase();
          data = data.filter(i => i.index.toLowerCase().includes(lowerQ));
      }
      else {
          // If not searching, show only Default Overview + Tracked Indices
          data = data.filter(i => 
              MARKET_OVERVIEW_INDICES.includes(i.index) || 
              trackedIndices.includes(i.index)
          );
      }

      // Sort: Tracked first, then by name
      return data.sort((a, b) => {
          const aTracked = trackedIndices.includes(a.index);
          const bTracked = trackedIndices.includes(b.index);
          if (aTracked && !bTracked) return -1;
          if (!aTracked && bTracked) return 1;
          return a.index.localeCompare(b.index);
      });
  }, [indicesData, filterQuery, trackedIndices]);

  useEffect(() => {
      const loadFii = async () => {
          const data = await fetchFiiDiiActivity(false);
          setFiiData(data);
      };
      loadFii();
  }, []);

  // Fetch Sectoral Data if not present
  useEffect(() => {
      if (!sectoralData) {
          loadSectorData('1D');
      }
  }, []);

  const loadSectorData = async (duration: string) => {
      setLoadingSector(true);
      try {
          const data = await fetchSectoralAnalysis(duration);
          setSectoralData(data);
      } catch (e) {
          console.error(e);
      } finally {
          setLoadingSector(false);
      }
  };

  const handleSectorDurationChange = (duration: string) => {
      setSectorDuration(duration);
      loadSectorData(duration);
  };

  const handleRefreshAll = async () => {
      onRefresh(); // Refresh indices
      const data = await fetchFiiDiiActivity(true); // Force refresh FII
      setFiiData(data);
      loadSectorData(sectorDuration); // Refresh Sector data
      if (onRefreshPortfolio) onRefreshPortfolio(); // Refresh Portfolio
  };

  const handleToggleTrack = (indexName: string) => {
      if (trackedIndices.includes(indexName)) {
          removeTrackedIndex(indexName);
      } else {
          addTrackedIndex(indexName);
      }
  };

  const TableHeader = () => (
      <thead className="bg-gray-50 text-gray-500 text-[10px] uppercase font-bold tracking-wider border-b border-gray-200 sticky top-0 z-10">
          <tr>
