        </div>

        {/* Section 2: Sectoral/Industrial Pulse */}
        <SectoralPulse 
            data={sectoralData}
            loading={loadingSector}
            onRefresh={() => loadSectorData(sectorDuration)}
            duration={sectorDuration}
            onDurationChange={handleSectorDurationChange}
            onAddMover={onAddMover}
            onSelectStock={onSelectStock}
            addedSymbols={moverSymbols}
        />

           {/* Section 3: Portfolio Updates */}
        <PortfolioUpdates 
            moversData={moversData} 
            onAddMover={onAddMover} 
            onRefreshMover={onRefreshMover}
            onRemoveMover={onRemoveMover}
            isLoadingExternal={loadingPortfolio || false}
            onViewDetails={onSelectStock} 
        />
    </div>

  );
};

export default MarketOverview;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { TrendingUp, Search, Plus, Check, Loader2, ChevronLeft, ChevronRight, Briefcase, CheckSquare, Square, ExternalLink, Globe, Trash2, RefreshCw } from 'lucide-react';
import { fetchStockQuote, searchStocksFromMasterList } from '../../services/dataService';
import { getTrackedIndices, getTrackedItems, addTrackedItem, removeTrackedItem } from '../../services/trackingStorage';
import { MARKET_OVERVIEW_INDICES, HEADER_INDICES } from '../../types/constants';
import PortfolioInsightsWidget from './PortfolioInsightsWidget';

interface PortfolioUpdatesProps {
  moversData: any[]; // The list of mover data objects
  onAddMover: (symbol: string) => Promise<void>;
  isLoadingExternal: boolean;
  onViewDetails?: (symbol: string, name: string) => void;
  onRefreshMover?: (symbol: string) => Promise<void>;
  onRemoveMover?: (symbol: string) => void;
}

const PortfolioUpdates: React.FC<PortfolioUpdatesProps> = ({ moversData, onAddMover, isLoadingExternal, onViewDetails, onRefreshMover, onRemoveMover }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Array<{ symbol: string; name: string }>>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showDropdown, setShowDropdown] = useState(false);
  const searchContainerRef = useRef<HTMLDivElement>(null);

  // Pagination State
  const [pageSize, setPageSize] = useState(10);
  const [currentPage, setCurrentPage] = useState(1);

  // Load Tracked Indices for comparison
  const [trackedIndices, setTrackedIndices] = useState<string[]>([]);
  const [trackedStockSet, setTrackedStockSet] = useState<Set<string>>(new Set());

  // Row refreshing state
  const [refreshingRows, setRefreshingRows] = useState<Set<string>>(new Set());

  useEffect(() => {
      setTrackedIndices(getTrackedIndices());
      refreshTrackedStocks();

      const handleUpdate = () => refreshTrackedStocks();
      window.addEventListener('fundflow_tracking_update', handleUpdate);
      return () => window.removeEventListener('fundflow_tracking_update', handleUpdate);
  }, []);

  // Close dropdown when clicking outside
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) {
              setShowDropdown(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const refreshTrackedStocks = () => {
      const items = getTrackedItems().filter(i => i.type === 'STOCK');
      setTrackedStockSet(new Set(items.map(i => i.id)));
  };

  const handleTrackToggle = (e: React.MouseEvent, symbol: string, name: string) => {
      e.stopPropagation();
      if (trackedStockSet.has(symbol)) {
          removeTrackedItem(symbol, 'STOCK');
          // If we remove from tracking, parent state should likely remove it from this table too (via event listener logic in parent)
      } else {
          addTrackedItem({ id: symbol, name: name, symbol, type: 'STOCK' });
      }
  };

  const handleRowRefresh = async (symbol: string) => {
      if (onRefreshMover) {
          setRefreshingRows(prev => new Set(prev).add(symbol));
          await onRefreshMover(symbol);
          setRefreshingRows(prev => {
              const next = new Set(prev);
              next.delete(symbol);
              return next;
          });
      }
  };

  // Expanded Search Logic using Master List
  useEffect(() => {
      const timeoutId = setTimeout(async () => {
          if (searchQuery.trim().length >= 2) {
              setIsSearching(true);
              setShowDropdown(true);
              try {
                  const results = await searchStocksFromMasterList(searchQuery);
                  // Do not filter out already added stocks; we will indicate them visually
                  setSearchResults(results);
              } catch (error) {
                  console.error("Search failed", error);
                  setSearchResults([]);
              } finally {
                  setIsSearching(false);
              }
          } else {
              setSearchResults([]);
              setShowDropdown(false);
          }
      }, 300);

      return () => clearTimeout(timeoutId);
  }, [searchQuery]);

  const handleAdd = async (symbol: string) => {
      await onAddMover(symbol);
      // Keep search active for multiple selections
  };

  // Pagination Logic
  const totalPages = Math.ceil(moversData.length / pageSize);
  const paginatedData = moversData.slice((currentPage - 1) * pageSize, currentPage * pageSize);

  useEffect(() => {
      if (currentPage > totalPages && totalPages > 0) {
          setCurrentPage(totalPages);
      }
  }, [moversData.length, totalPages]);

  // Combine all indices that are relevant to the dashboard (User Tracked + Default Market Overview + Headers)
  const allDashboardIndices = useMemo(() => {
      const combined = new Set([
          ...trackedIndices,
          ...MARKET_OVERVIEW_INDICES,
          ...HEADER_INDICES
      ]);
      return Array.from(combined);
  }, [trackedIndices]);

  // Prepare list of symbols currently in the table to pass to the widget
  const currentTableSymbols = useMemo(() => moversData.map(m => m.symbol), [moversData]);

  return (
    <div className="space-y-4">
       <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
           <div className="flex items-center gap-2">
               <div className="p-1.5 bg-indigo-50 text-indigo-600 rounded-lg">
                   <TrendingUp size={18} />
               </div>
               <h3 className="text-lg font-bold text-gray-900">Portfolio Updates</h3>
               {moversData.length > 0 && (
                   <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">
                       {moversData.length}
                   </span>
               )}
           </div>

           {/* Search Input */}
           <div className="relative w-full sm:w-80 z-20" ref={searchContainerRef}>
               <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                   <Search size={14} className="text-gray-400" />
               </div>
               <input 
                   type="text"
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   onFocus={() => { if(searchQuery.length >= 2) setShowDropdown(true); }}
                   placeholder="Search stock to add (e.g. RELIANCE)..."
                   className="w-full bg-white border border-gray-200 text-gray-700 text-sm rounded-lg pl-9 pr-3 py-1.5 focus:outline-none focus:ring-2 focus:ring-indigo-500"
               />
               {isLoadingExternal && (
                   <div className="absolute inset-y-0 right-0 flex items-center pr-3">
                       <Loader2 size={14} className="animate-spin text-indigo-600" />
                   </div>
               )}

               {/* Dropdown Results */}
               {showDropdown && searchQuery && (
                   <div className="absolute top-full left-0 right-0 mt-1 bg-white rounded-lg shadow-lg border border-gray-200 max-h-60 overflow-y-auto">
                       {isSearching ? (
                           <div className="p-3 text-center text-xs text-gray-400">Searching...</div>
                       ) : searchResults.length > 0 ? (
                           searchResults.map(res => {
                               const isAdded = moversData.some(m => m.symbol === res.symbol);
                               return (
                                   <div 
                                       key={res.symbol}
                                       onClick={() => !isAdded && handleAdd(res.symbol)}
                                       className={`px-4 py-2 text-sm flex items-center justify-between border-b border-gray-50 last:border-0 group transition-colors ${
                                           isAdded ? 'cursor-default bg-gray-50 opacity-70' : 'cursor-pointer hover:bg-gray-50'
                                       }`}
                                   >
                                       <div className="flex flex-col">
                                           <span className={`font-bold text-xs ${isAdded ? 'text-gray-500' : 'text-gray-800'}`}>{res.symbol}</span>
                                           <span className="text-[10px] text-gray-500 truncate max-w-[200px]">{res.name}</span>
                                       </div>
                                       {isAdded ? (
                                           <Check size={14} className="text-green-600" />
                                       ) : (
                                           <Plus size={14} className="text-gray-400 group-hover:text-indigo-600" />
                                       )}
                                   </div>
                               );
                           })
                       ) : (
                           <div className="p-3 text-center text-xs text-gray-400">
                               No matching stocks found.
                           </div>
                       )}
                   </div>
               )}
           </div>
       </div>

       <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col min-h-[150px]">
           {moversData.length === 0 ? (
               <div className="flex-1 flex flex-col items-center justify-center p-8 text-center text-gray-400 text-sm gap-2">
                   {isLoadingExternal ? (
                       <>
                           <Loader2 size={24} className="animate-spin text-indigo-500" />
                           <span>Loading tracked stocks...</span>
                       </>
                   ) : (
                       <span>No stocks tracked yet. Use the search bar to add stocks to your portfolio updates.</span>
                   )}
               </div>
           ) : (
               <>
                   <div className="overflow-x-auto">
                       <table className="w-full text-xs text-left whitespace-nowrap">
                           <thead className="bg-gray-50 text-gray-500 font-bold uppercase tracking-wider border-b border-gray-200">
                               <tr>
                                   <th className="px-4 py-3 w-10"></th> {/* Tracking Checkbox */}
                                   <th className="px-4 py-3">Stock</th>
                                   <th className="px-4 py-3 text-right">Price (Chg%)</th>
                                   <th className="px-4 py-3 text-center">Valuation</th>
                                   <th className="px-4 py-3 text-center">Delivery</th>
                                   <th className="px-4 py-3 text-center">Sec. Index</th>
                                   <th className="px-4 py-3">Sector</th>
                                   <th className="px-4 py-3 text-center w-28">52W Range</th>
                                   <th className="px-4 py-3">Tracked Via</th>
                                   <th className="px-4 py-3 text-right">Actions</th>
                               </tr>
                           </thead>
                           <tbody className="bg-white divide-y divide-gray-50">
                               {paginatedData.map((stock, idx) => {
                                   const isPos = stock.change >= 0;
                                   const rangePos = ((stock.lastPrice - stock.yearLow) / (stock.yearHigh - stock.yearLow)) * 100;
                                   const isTracked = trackedStockSet.has(stock.symbol);
                                   const isRowRefreshing = refreshingRows.has(stock.symbol);

                                   // Identify matching indices (Case Insensitive Check)
                                   const matchedIndices = stock.indexList?.filter((idxName: string) => 
                                       allDashboardIndices.some(dashboardIdx => dashboardIdx.toLowerCase() === idxName.toLowerCase())
                                   ) || [];

                                   const sectorTooltip = [stock.macro, stock.sector, stock.basicIndustry].filter(Boolean).join(" > ");

                                   // Generate NSE Link
                                   const companySlug = stock.companyName ? stock.companyName.replace(/\s+/g, '-') : '';
                                   const nseUrl = `https://www.nseindia.com/get-quote/equity/${encodeURIComponent(stock.symbol)}/${encodeURIComponent(companySlug)}`;

                                   // Logic for Sector Index Display (Priority: pdSectorInd -> indexList[0])
                                   let displaySectorIndex = stock.pdSectorInd;
                                   if (!displaySectorIndex || displaySectorIndex === '-') {
                                       displaySectorIndex = stock.indexList && stock.indexList.length > 0 ? stock.indexList[0] : null;
                                   }

                                   return (
                                       <tr key={`${stock.symbol}-${idx}`} className="hover:bg-gray-50 transition-colors">
                                           {/* Tracking Checkbox */}
                                           <td className="px-4 py-3 text-center">
                                                <button 
                                                    onClick={(e) => handleTrackToggle(e, stock.symbol, stock.companyName)}
                                                    className={`transition-colors ${isTracked ? 'text-indigo-600' : 'text-gray-300 hover:text-gray-500'}`}
                                                    title={isTracked ? "Remove from Watchlist" : "Add to Watchlist"}
                                                >
                                                    {isTracked ? <CheckSquare size={16} /> : <Square size={16} />}
                                                </button>
                                           </td>

                                           <td className="px-4 py-3">
                                               <div 
                                                    className="flex flex-col group cursor-pointer"
                                                    onClick={() => onViewDetails && onViewDetails(stock.symbol, stock.companyName)}
                                               >
                                                   <div className="flex items-center gap-1.5">
                                                       <span className="font-bold text-indigo-700 group-hover:underline">
                                                           {stock.symbol}
                                                       </span>

                                                       {/* Widget Icon wrapped to prevent click propagation if needed, handled inside component though */}
                                                       <div onClick={(e) => e.stopPropagation()}>
                                                           <PortfolioInsightsWidget 
                                                                onAddToMover={async (s) => { if (!moversData.some(m => m.symbol === s)) await onAddMover(s) }}
                                                                onNavigateStock={onViewDetails}
                                                                addedSymbols={currentTableSymbols}
                                                                initialSymbolContext={stock.symbol}
                                                           />
                                                       </div>

                                                       <a 
                                                            href={nseUrl} 
                                                            target="_blank" 
                                                            rel="noreferrer" 
                                                            className="text-gray-300 hover:text-indigo-600 transition-colors opacity-0 group-hover:opacity-100"
                                                            title="View on NSE India"
                                                            onClick={(e) => e.stopPropagation()}
                                                       >
                                                           <ExternalLink size={12} />
                                                       </a>
                                                   </div>
                                                   <div className="text-[10px] text-gray-500 truncate max-w-[140px]" title={stock.companyName}>
                                                       {stock.companyName}
                                                   </div>
                                               </div>
                                           </td>
                                           <td className="px-4 py-3 text-right">
                                               <div className={`font-mono font-medium text-gray-800 ${isRowRefreshing ? 'opacity-50' : ''}`}>
                                                   {stock.lastPrice?.toLocaleString() ?? '-'} 
                                                   <span className={`ml-1 text-[10px] ${isPos ? 'text-green-600' : 'text-red-600'}`}>
                                                       ({isPos ? '+' : ''}{stock.pChange}%)
                                                   </span>
                                               </div>
                                           </td>
                                           <td className="px-4 py-3 text-center">
                                               <div className="flex flex-col items-center">
                                                   {stock.pdSymbolPe && stock.pdSymbolPe !== '-' ? (
                                                       <span className="font-medium text-gray-700 bg-gray-100 px-1.5 py-0.5 rounded">
                                                           {stock.pdSymbolPe}
                                                       </span>
                                                   ) : <span className="text-gray-300">-</span>}
                                                   <span className="text-[9px] text-gray-400 mt-0.5">
                                                       Sec: {stock.pdSectorPe || '-'}
                                                   </span>
                                               </div>
                                           </td>
                                           <td className="px-4 py-3 text-center font-mono text-gray-600 text-xs">
                                               {stock.delivery ? `${stock.delivery}%` : '-'}
                                           </td>
                                           <td className="px-4 py-3 text-center">
                                               {displaySectorIndex && displaySectorIndex !== '-' ? (
                                                   <span className="bg-blue-50 text-blue-700 px-1.5 py-0.5 rounded text-[10px] whitespace-nowrap">
                                                       {displaySectorIndex}
                                                   </span>
                                               ) : <span className="text-gray-300">-</span>}
                                           </td>
                                           <td className="px-4 py-3">
                                               <span 
                                                    className="text-gray-600 truncate max-w-[120px] block cursor-help decoration-dotted underline underline-offset-2" 
                                                    title={sectorTooltip}
                                               >
                                                   {stock.basicIndustry || stock.sector || '-'}
                                               </span>
                                           </td>
                                           <td className="px-4 py-3 text-center">
                                               <div className="flex flex-col gap-1 w-full max-w-[100px] mx-auto">
                                                   <div className="flex justify-between text-[9px] text-gray-400">
                                                       <span>{stock.yearLow?.toLocaleString() ?? '-'}</span>
                                                       <span>{stock.yearHigh?.toLocaleString() ?? '-'}</span>
                                                   </div>
                                                   <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden relative">
                                                       <div 
                                                           className="absolute h-full w-1.5 bg-indigo-600 rounded-full top-0 ml-[-3px]" 
                                                           style={{ left: `${Math.min(Math.max(rangePos || 0, 0), 100)}%` }}
                                                       ></div>
                                                   </div>
                                               </div>
                                           </td>
                                           <td className="px-4 py-3">
                                               <div className="flex flex-wrap gap-1 max-w-[200px]">
                                                   {matchedIndices.length > 0 ? matchedIndices.map((idxName: string) => (
                                                       <span key={idxName} className="px-1.5 py-0.5 bg-orange-50 text-orange-700 border border-orange-100 rounded text-[9px]">
                                                           {idxName}
                                                       </span>
                                                   )) : (
                                                       <span className="text-gray-300 text-[10px] italic">None</span>
                                                   )}
                                               </div>
                                           </td>
                                           {/* Actions Column */}
                                           <td className="px-4 py-3 text-right">
                                               <div className="flex items-center justify-end gap-2">
                                                   <button 
                                                       onClick={() => handleRowRefresh(stock.symbol)}
                                                       disabled={isRowRefreshing}
                                                       className="p-1.5 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded transition-colors"
                                                       title="Refresh Stock Data"
                                                   >
                                                       <RefreshCw size={14} className={isRowRefreshing ? 'animate-spin text-indigo-600' : ''} />
                                                   </button>
                                                   {onRemoveMover && (
                                                       <button 
                                                           onClick={() => onRemoveMover(stock.symbol)}
                                                           className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded transition-colors"
                                                           title="Remove from Table"
                                                       >
                                                           <Trash2 size={14} />
                                                       </button>
                                                   )}
                                               </div>
                                           </td>
                                       </tr>
                                   );
                               })}
                           </tbody>
                       </table>
                   </div>

                   {/* Pagination */}
                   <div className="px-4 py-3 border-t border-gray-200 flex items-center justify-between bg-gray-50">
                       <div className="flex items-center gap-2">
                           <span className="text-xs text-gray-500">Rows:</span>
                           <select 
                               value={pageSize} 
                               onChange={(e) => { setPageSize(Number(e.target.value)); setCurrentPage(1); }}
                               className="bg-white border border-gray-200 text-gray-700 text-xs rounded-lg p-1 focus:ring-indigo-500 focus:border-indigo-500"
                           >
                               <option value={5}>5</option>
                               <option value={10}>10</option>
                               <option value={20}>20</option>
                           </select>
                       </div>

                       <div className="flex items-center gap-2">
                           <button
                               onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                               disabled={currentPage === 1}
                               className="p-1 rounded-md bg-white border border-gray-200 hover:bg-gray-100 disabled:opacity-50 text-gray-600"
                           >
                               <ChevronLeft size={14} />
                           </button>
                           <span className="text-xs text-gray-600 font-medium">
                               {currentPage} / {totalPages || 1}
                           </span>
                           <button
                               onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                               disabled={currentPage === totalPages || totalPages === 0}
                               className="p-1 rounded-md bg-white border border-gray-200 hover:bg-gray-100 disabled:opacity-50 text-gray-600"
                           >
                               <ChevronRight size={14} />
                           </button>
                       </div>
                   </div>
               </>
           )}
       </div>
    </div>
  );
};

export default PortfolioUpdates;

import React, { useState, useEffect, useMemo } from 'react';
import { Loader2, RefreshCw, Filter, BrainCircuit, ChevronDown, ChevronLeft, ChevronRight, Search, EyeOff, Plus } from 'lucide-react';
import { fetchIndexConstituents } from '../../services/dataService';
import { processIndicatorData, ProcessedInsight } from '../../services/indicatorProcessor';
import { isTracked, addTrackedItem, removeTrackedItem, getTrackedIndices, getIgnoredItems, addIgnoredItem } from '../../services/trackingStorage';
import IntelligentStockCard from './cards/IntelligentStockCard';
import { InsightResultItem, IntelligentState } from '../../types/trackingTypes';

interface IntelligentTrackingManagerProps {
  onOpenChat: (context: any[]) => void;
  onSelectStock: (symbol: string, name: string) => void;
  // Props from parent hook
  extractionData: {
      results: Record<string, InsightResultItem[]>;
      status: 'idle' | 'initializing' | 'polling' | 'completed' | 'error';
      startExtraction: (symbols: string[], batchSize?: number, invalidateCache?: boolean) => Promise<void>;
      progress: { completed: number; total: number };
  };
  onStatsUpdate: (stats: { filtered: number; total: number; ignoredList: string[] }) => void;
  // Persisted View State
  viewState: IntelligentState;
  setViewState: React.Dispatch<React.SetStateAction<IntelligentState>>;
}

const FILTER_TYPES: string[] = ["All", "Valuation", "Technicals", "Holdings", "Performance", "Deals"];
const BATCH_SIZE = 10;

const IntelligentTrackingManager: React.FC<IntelligentTrackingManagerProps> = ({ 
  onOpenChat, 
  onSelectStock,
  extractionData,
  onStatsUpdate,
  viewState,
  setViewState
}) => {
  const [loadingSymbols, setLoadingSymbols] = useState(false);
  const [trackTick, setTrackTick] = useState(0);
  const [availableIndices, setAvailableIndices] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState<string>('');

  // Selection and Force Refresh State
  const [selectedSymbols, setSelectedSymbols] = useState<Set<string>>(new Set());
  const [forceRefresh, setForceRefresh] = useState(false);

  // Ignore list state to filter locally
  const [ignoredItems, setIgnoredItems] = useState<string[]>([]);

  // Current Index Ignored List
  const [currentIndexIgnored, setCurrentIndexIgnored] = useState<string[]>([]);

  // Destructure hook data
  const { results, status, startExtraction, progress } = extractionData;

  // Local state for processed trigger data (Derived from results, so safe to be local)
  const [processedStocks, setProcessedStocks] = useState<Record<string, ProcessedInsight[]>>({});
  const [processingData, setProcessingData] = useState(false);

  // Helper to update specific view state fields
  const updateState = (updates: Partial<IntelligentState>) => {
      setViewState(prev => ({ ...prev, ...updates }));
  };

  // 0. Load Available Indices & Ignored List
  useEffect(() => {
    const loadData = () => {
        const indices = getTrackedIndices();
        setAvailableIndices(indices);
        setIgnoredItems(getIgnoredItems());

        // Safety check: if current selected index was deleted, default to first available
        if (indices.length > 0 && !indices.includes(viewState.selectedIndex)) {
            updateState({ selectedIndex: indices[0], symbols: [], page: 1 });
        }
    };
    loadData();

    // Listen for storage changes
    const handleUpdate = () => loadData();
    window.addEventListener('fundflow_tracking_update', handleUpdate);
    return () => window.removeEventListener('fundflow_tracking_update', handleUpdate);
  }, [viewState.selectedIndex]);

  // 1. Fetch Index Symbols on Change (Persisted in viewState.symbols)
  useEffect(() => {
     // If we already have symbols for this index, we still need to re-calculate ignored items 
     // because ignore list might have changed.

     // Only fetch if we have a valid selected index
     if (!viewState.selectedIndex) return;

     const loadSymbols = async () => {
         // Avoid re-fetching API if we just want to re-filter
         const alreadyLoaded = viewState.symbols.length > 0 && !loadingSymbols;

         if(!alreadyLoaded) setLoadingSymbols(true);

         try {
             // For simplicity, we always refetch constituents to ensure we get the full list for calculating ignored
             // Optimization: We could cache raw index response
             const allSymbols = await fetchIndexConstituents(viewState.selectedIndex);

             const ignored = getIgnoredItems();
             const ignoredInIndex = allSymbols.filter(s => ignored.includes(s));
             const cleanSymbols = allSymbols.filter(s => !ignored.includes(s));

             setCurrentIndexIgnored(ignoredInIndex);

             // Only update viewState if it actually changed (shallow check optimization implied)
             if (!alreadyLoaded || cleanSymbols.length !== viewState.symbols.length) {
                 updateState({ symbols: cleanSymbols, page: 1 }); 
                 setSelectedSymbols(new Set());
             }
         } catch (e) {
             console.error("Failed to fetch index symbols", e);
             updateState({ symbols: [] });
         } finally {
             setLoadingSymbols(false);
         }
     };
     loadSymbols();
  }, [viewState.selectedIndex, trackTick]); // re-run if tracking/ignore list changes (trackTick updates on ignore action)

  // 2. Start Extraction logic (Smart Refresh for Missing Symbols)
  useEffect(() => {
      const isFetching = status === 'initializing' || status === 'polling';
      if (viewState.symbols.length === 0 || isFetching) return;

      // Identify which symbols in the current view don't have results yet
      const missingSymbols = viewState.symbols.filter(sym => !results[sym] || results[sym].length === 0);

      if (missingSymbols.length > 0) {
          // Fetch only the missing ones (no force refresh for auto-fetch)
          startExtraction(missingSymbols, BATCH_SIZE, false);
      }
  }, [viewState.symbols, status, results, startExtraction]);

  // 3. Process Raw Results into Intelligent Insights
  useEffect(() => {
      const processResults = async () => {
          if (Object.keys(results).length === 0) {
              setProcessedStocks({});
              return;
          }

          setProcessingData(true);
          const newProcessed: Record<string, ProcessedInsight[]> = {};

          for (const [symbol, val] of Object.entries(results)) {
              // Ensure we are working with correct types, casting to any first helps if inference is unknown
              const items = (val as any) as InsightResultItem[];
              // Optimization: Only process symbols relevant to current index to save performance
              if (!viewState.symbols.includes(symbol)) continue;

              const stockInsights: ProcessedInsight[] = [];
              for (const item of items) {
                  if (item.success && (item.type === 'json' || item.data)) {
                       const insight = await processIndicatorData(symbol, item.indicatorName as string, item.data);
                       if (insight.status === 'triggered') {
                           stockInsights.push(insight);
                       }
                  }
              }
              if (stockInsights.length > 0) {
                  newProcessed[symbol] = stockInsights;
              }
          }
          setProcessedStocks(newProcessed);
          setProcessingData(false);
      };

      const timer = setTimeout(processResults, 1000);
      return () => clearTimeout(timer);
  }, [results, viewState.symbols]);

  // 4. Filter Logic
  const filteredStocks = useMemo(() => {
      return (Object.entries(processedStocks) as [string, ProcessedInsight[]][]).filter(([symbol, insights]) => {
          // 0. Double check ignore list
          if (ignoredItems.includes(symbol)) return false;

          // 1. Filter by Insight Type
          const matchesType = viewState.filter === "All" || insights.some(i => i.type === viewState.filter);
          if (!matchesType) return false;

          // 2. Filter by Search Query
          if (!searchQuery) return true;
          const lowerQ = searchQuery.toLowerCase();

          if (symbol.toLowerCase().includes(lowerQ)) return true;
          if (insights.some(i => i.text?.toLowerCase().includes(lowerQ))) return true;

          return false;
      }).sort((a, b) => b[1].length - a[1].length); 
  }, [processedStocks, viewState.filter, searchQuery, ignoredItems]);

  // 5. Pagination Logic
  const paginatedStocks = useMemo(() => {
      const startIndex = (viewState.page - 1) * viewState.pageSize;
      return filteredStocks.slice(startIndex, startIndex + viewState.pageSize);
  }, [filteredStocks, viewState.page, viewState.pageSize]);

  const totalPages = Math.ceil(filteredStocks.length / viewState.pageSize);

  // 6. Update Parent Stats
  useEffect(() => {
      onStatsUpdate({
          filtered: filteredStocks.length,
          total: viewState.symbols.length,
          ignoredList: currentIndexIgnored
      });
  }, [filteredStocks.length, viewState.symbols.length, currentIndexIgnored, onStatsUpdate]);

  const handleToggleSelect = (symbol: string) => {
      const newSet = new Set(selectedSymbols);
      if (newSet.has(symbol)) {
          newSet.delete(symbol);
      } else {
          newSet.add(symbol);
      }
      setSelectedSymbols(newSet);
  };

  const handleManualRefresh = () => {
      if (selectedSymbols.size > 0) {
          startExtraction(Array.from(selectedSymbols), BATCH_SIZE, true);
          setSelectedSymbols(new Set()); 
      } else if (viewState.symbols.length > 0) {
          startExtraction(viewState.symbols, BATCH_SIZE, forceRefresh);
      }
  };

  const handleIgnoreSelected = () => {
      if (selectedSymbols.size === 0) return;

      const toIgnore = Array.from(selectedSymbols);
      toIgnore.forEach(sym => addIgnoredItem(sym));

      setTrackTick(prev => prev + 1);
      setSelectedSymbols(new Set());
  };

  const handleTrackSelected = () => {
      if (selectedSymbols.size === 0) return;

      const toTrack = Array.from(selectedSymbols);
      toTrack.forEach(sym => {
          // Use symbol as name if full name isn't readily available in this context
          addTrackedItem({ id: sym, name: sym, symbol: sym, type: 'STOCK' });
      });

      setTrackTick(prev => prev + 1);
      setSelectedSymbols(new Set());
  };

  const handleCardRefresh = (symbol: string) => {
      startExtraction([symbol], 1, true);
  };

  return (
    <div className="space-y-6">
       {/* Controls Bar */}
       <div className="bg-white rounded-xl border border-gray-200 p-4 flex flex-col xl:flex-row items-center justify-between gap-4 shadow-sm">

           <div className="flex flex-col md:flex-row items-center gap-4 w-full xl:w-auto">
               {/* Index Selector */}
               <div className="relative w-full md:w-48">
                   <select 
                       value={viewState.selectedIndex}
                       onChange={(e: React.ChangeEvent<HTMLSelectElement>) => {
                           updateState({ selectedIndex: e.target.value, symbols: [], page: 1 }); 
                       }}
                       className="w-full appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-4 pr-10 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer"
                       disabled={loadingSymbols || status === 'initializing'}
                   >
                       {availableIndices.map((idx: string) => <option key={idx} value={idx}>{idx}</option>)}
                   </select>
                   <ChevronDown size={16} className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" />
               </div>

                {/* Search Box */}
               <div className="relative w-full md:w-48">
                   <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                        <Search size={16} className="text-gray-400" />
                   </div>
                   <input 
                       type="text"
                       value={searchQuery}
                       onChange={(e) => setSearchQuery(e.target.value)}
                       placeholder="Search insights..."
                       className="w-full bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-9 pr-3 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                   />
               </div>

               <div className="h-6 w-px bg-gray-200 hidden md:block"></div>

               {/* Filter Dropdown */}
               <div className="relative w-full md:w-48">
                   <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                        <Filter size={16} className="text-gray-400" />
                   </div>
                   <select 
                       value={viewState.filter}
                       onChange={(e: React.ChangeEvent<HTMLSelectElement>) => updateState({ filter: e.target.value, page: 1 })}
                       className="w-full appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-9 pr-10 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer"
                   >
                       {FILTER_TYPES.map((type: string) => (
                           <option key={type} value={type}>{type} Insights</option>
                       ))}
                   </select>
                   <ChevronDown size={16} className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" />
               </div>

                {/* Force Refresh Checkbox (Only visible if no selection, as selection implies force) */}
               {selectedSymbols.size === 0 && (
                   <label className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer whitespace-nowrap ml-2">
                       <input 
                           type="checkbox" 
                           checked={forceRefresh} 
                           onChange={(e) => setForceRefresh(e.target.checked)}
                           className="w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                       />
                       Invalidate Cache
                   </label>
               )}
           </div>

           {/* Right Side: Pagination & Status */}
           <div className="flex items-center gap-4 w-full xl:w-auto justify-between xl:justify-end">

               {filteredStocks.length > 0 && (
                   <div className="flex items-center gap-3">
                       <div className="flex items-center gap-2">
                           <span className="text-xs text-gray-500">Rows:</span>
                           <select 
                             value={viewState.pageSize} 
                             onChange={(e) => updateState({ pageSize: Number(e.target.value), page: 1 })}
                             className="bg-gray-50 border border-gray-200 text-gray-700 text-xs rounded-lg p-1.5"
                           >
                               <option value={10}>10</option>
                               <option value={20}>20</option>
                               <option value={50}>50</option>
                               <option value={100}>100</option>
                           </select>
                       </div>

                       <div className="flex items-center gap-1">
                            <button
                                onClick={() => updateState({ page: Math.max(1, viewState.page - 1) })}
                                disabled={viewState.page === 1}
                                className="p-1.5 rounded-md border border-gray-200 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <ChevronLeft size={16} />
                            </button>
                            <span className="text-xs font-medium w-16 text-center">
                                {viewState.page} / {totalPages}
                            </span>
                            <button
                                onClick={() => updateState({ page: Math.min(totalPages, viewState.page + 1) })}
                                disabled={viewState.page === totalPages}
                                className="p-1.5 rounded-md border border-gray-200 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <ChevronRight size={16} />
                            </button>
                       </div>
                   </div>
               )}

               <div className="h-6 w-px bg-gray-200 hidden xl:block"></div>

               {loadingSymbols ? (
                   <span className="text-xs text-gray-500 flex items-center gap-2">
                       <Loader2 size={14} className="animate-spin" /> Fetching Symbols...
                   </span>
               ) : status === 'initializing' || status === 'polling' ? (
                   <div className="flex items-center gap-3">
                       <span className="text-xs text-gray-500 flex items-center gap-2">
                           <Loader2 size={14} className="animate-spin text-indigo-600" /> 
                           Analyzing {progress.completed}/{progress.total}
                       </span>
                   </div>
               ) : selectedSymbols.size > 0 ? (
                   <div className="flex items-center gap-2">
                       <button 
                           onClick={handleTrackSelected}
                           className="flex items-center gap-2 px-3 py-2 bg-green-50 text-green-600 hover:bg-green-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Add selected to Watchlist"
                       >
                           <Plus size={16} />
                           Track ({selectedSymbols.size})
                       </button>
                       <button 
                           onClick={handleIgnoreSelected}
                           className="flex items-center gap-2 px-3 py-2 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Add selected to Ignore List (Do not track)"
                       >
                           <EyeOff size={16} />
                           Ignore ({selectedSymbols.size})
                       </button>
                       <button 
                           onClick={handleManualRefresh}
                           className="flex items-center gap-2 px-3 py-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Force Refresh Selected"
                       >
                           <RefreshCw size={16} />
                           Refresh
                       </button>
                   </div>
               ) : (
                   <button 
                       onClick={handleManualRefresh}
                       className="p-2 text-gray-600 hover:text-indigo-600 hover:bg-gray-50 rounded-lg transition-colors border border-transparent hover:border-gray-200"
                       title="Refresh List"
                   >
                       <RefreshCw size={20} />
                   </button>
               )}
           </div>
       </div>

       {/* Content Grid */}
       {loadingSymbols ? (
           <div className="flex flex-col items-center justify-center py-20 text-gray-400">
               <Loader2 size={32} className="animate-spin text-indigo-500 mb-2" />
               <p className="text-sm">Loading Index Constituents...</p>
           </div>
       ) : paginatedStocks.length > 0 ? (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
               {paginatedStocks.map(([symbol, insights]) => (
                   <IntelligentStockCard 
                       key={symbol}
                       symbol={symbol}
                       insights={insights}
                       isTracked={isTracked(symbol, 'STOCK')}
                       onOpenDeepDive={() => onSelectStock(symbol, symbol)}
                       onAskAI={() => onOpenChat(insights.map(i => ({ 
                           symbol, 
                           type: i.type || 'General', 
                           insight: i.text || '', 
                           rawData: i.data 
                       })))}
                       onRefresh={() => handleCardRefresh(symbol)}
                       isSelected={selectedSymbols.has(symbol)}
                       onToggleSelect={() => handleToggleSelect(symbol)}
                   />
               ))}
           </div>
       ) : (
           <div className="flex flex-col items-center justify-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
               {status === 'initializing' || status === 'polling' || processingData ? (
                   <>
                      <BrainCircuit size={48} className="text-indigo-200 mb-4 animate-pulse" />
                      <h3 className="text-lg font-medium text-gray-900">Analysis in Progress</h3>
                      <p className="text-gray-500 mt-1">Processing data in batches of {BATCH_SIZE}...</p>
                   </>
               ) : (
                   <>
                      <p className="text-gray-500">No stocks found matching your criteria.</p>
                      <p className="text-xs text-gray-400 mt-1">Try changing the filter, search query, or refreshing analysis.</p>
                   </>
               )}
           </div>
       )}
    </div>
  );
};

export default IntelligentTrackingManager;
